import{toDependency,toEntry}from"../../util/input.js";import{hasDependency}from"../../util/plugin.js";import{clientToPackages}from"./helpers.js";const title="Knex",enablers=["knex"],isEnabled=({dependencies:e})=>hasDependency(e,enablers),config=["knexfile.{js,cjs,mjs,ts,cts,mts}"],processKnexConfig=e=>{const n=[];if(e.client){const s=clientToPackages(e.client);n.push(...s.map(e=>toDependency(e,{optional:!0})))}if(e.migrations?.directory){const s=Array.isArray(e.migrations.directory)?e.migrations.directory:[e.migrations.directory];n.push(...s.map(e=>toEntry(`${e}/*.{js,ts}`)))}if(e.seeds?.directory){const s=Array.isArray(e.seeds.directory)?e.seeds.directory:[e.seeds.directory];n.push(...s.map(e=>toEntry(`${e}/*.{js,ts}`)))}return n},resolveConfig=e=>("client"in e&&e.client?[e]:Object.values(e)).flatMap(e=>"object"==typeof e&&null!==e?processKnexConfig(e):[]),plugin={title:title,enablers:enablers,isEnabled:isEnabled,config:config,resolveConfig:resolveConfig};export default plugin;